export function parseInitiateWagerInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedInitiateWagerInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 10) {
    // TODO: Coded error.
    throw new Error("Not enough accounts");
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  const getNextOptionalAccount = () => {
    const accountMeta = getNextAccount();
    return accountMeta.address === DICE_DUEL_PROGRAM_ADDRESS
      ? undefined
      : accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      challenger: getNextAccount(),
      challengerBag: getNextAccount(),
      challengerStats: getNextAccount(),
      wager: getNextAccount(),
      escrow: getNextAccount(),
      config: getNextAccount(),
      gameTypeAccount: getNextAccount(),
      prevWager: getNextOptionalAccount(),
      prevEscrow: getNextOptionalAccount(),
      systemProgram: getNextAccount(),
    },
    data: getInitiateWagerInstructionDataDecoder().decode(instruction.data),
  };
}
